parameters.inputSchema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.com/hr-triage.schema.json",
  "title": "HR Triage Classification Output",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "ticket_title",
    "summary",
    "category",
    "eisenhower_quadrant",
    "urgency",
    "importance",
    "effort",
    "risk",
    "confidence",
    "should_create_ticket",
    "suggested_assignee_role",
    "suggested_due_date",
    "draft_reply"
  ],
  "properties": {
    "ticket_title": {
      "type": "string",
      "minLength": 1,
      "maxLength": 90,
      "description": "Short ticket title, ideally 6 to 10 words."
    },
    "summary": {
      "type": "string",
      "minLength": 1,
      "maxLength": 140,
      "description": "Short summary, max about 20 words."
    },
    "category": {
      "type": "string",
      "enum": ["Payroll", "Time off", "Contract", "Hiring", "IT", "Facilities", "Finance", "Other"]
    },
    "eisenhower_quadrant": {
      "type": "string",
      "enum": ["DoNow", "Plan", "Delegate", "Defer"]
    },
    "urgency": {
      "type": "integer",
      "minimum": 0,
      "maximum": 10
    },
    "importance": {
      "type": "integer",
      "minimum": 0,
      "maximum": 10
    },
    "effort": {
      "type": "integer",
      "minimum": 0,
      "maximum": 10
    },
    "risk": {
      "type": "integer",
      "minimum": 0,
      "maximum": 10,
      "description": "Risk includes legal, compliance, reputation, escalation potential."
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    },
    "should_create_ticket": {
      "type": "boolean"
    },
    "suggested_assignee_role": {
      "type": "string",
      "enum": ["HR Ops", "Recruiter", "People Lead", "IT", "Finance"]
    },
    "suggested_due_date": {
      "type": "string",
      "format": "date",
      "description": "ISO 8601 date, for example 2026-01-25."
    },
    "draft_reply": {
      "type": "string",
      "minLength": 1,
      "maxLength": 600,
      "description": "One short reply suitable for Slack or email."
    }
  }
}

